% ----- Absolute-cohomology functor infrastructure for the transport route -----

\begin{lemma}
[The presheaf-of-modules functor is additive]
  \label{lem:toPresheafOfModules_additive}
  \lean{AlgebraicGeometry.toPresheafOfModules_additive}
  The functor \(\operatorname{toPresheafOfModules} X : X.\mathrm{Modules} \to
  \mathrm{PresheafOfModules}(\mathcal{O}_X)\), sending a sheaf of \(\mathcal{O}_X\)-modules to its
  underlying presheaf of modules, is additive: it preserves finite biproducts and the additive
  structure on hom-groups.
\end{lemma}
\begin{proof}
  The functor is the composite of the forgetful functor
  \(\mathrm{SheafOfModules}(\mathcal{O}_X) \to \mathrm{PresheafOfModules}(\mathcal{O}_X)\) and the
  restriction of scalars along the identity \(\operatorname{restrictScalars}(\mathrm{id}_{\mathcal{O}_X})\).
  Both factors are additive, and a composite of additive functors is additive.
\end{proof}

\begin{lemma}
[The sections functor is additive]
  \label{lem:sectionsFunctor_additive}
  \lean{AlgebraicGeometry.sectionsFunctor_additive}
  \uses{lem:toPresheafOfModules_additive}
  For an open \(V \subseteq X\) the global-sections functor
  \(\operatorname{sectionsFunctor} V = \Gamma(V, -) : X.\mathrm{Modules} \to \mathrm{Ab}\) is
  additive.
\end{lemma}
\begin{proof}
  \uses{lem:toPresheafOfModules_additive}
  The functor factors as the additive functor to presheaves of modules
  (Lemma~\ref{lem:toPresheafOfModules_additive}), followed by the underlying-presheaf functor and
  evaluation at \(V\), each of which is additive; the composite is therefore additive.
\end{proof}

\begin{lemma}
[The sections functor is corepresented by \(j_!\mathcal{O}_V\)]
  \label{lem:sectionsFunctorCorepIso}
  \lean{AlgebraicGeometry.sectionsFunctorCorepIso}
  \uses{lem:jshriek_corepr, lem:sectionsFunctor_additive}
  For an open \(V \subseteq X\) there is a natural isomorphism of additive functors
  \[
    \operatorname{sectionsFunctor} V
      \;\cong\;
    \operatorname{Hom}_{X.\mathrm{Modules}}\bigl(j_!\mathcal{O}_V,\, -\bigr)
  \]
  between \(\Gamma(V, -)\) and the covariant additive hom-functor corepresented by
  \(j_!\mathcal{O}_V\). It is the functorial upgrade of the corepresentability bijection of
  Lemma~\ref{lem:jshriek_corepr}.
\end{lemma}
\begin{proof}
  \uses{lem:jshriek_corepr, lem:sectionsFunctor_additive}
  Assemble the natural transformation from the additive corepresentability isomorphism
  \(\operatorname{Hom}(j_!\mathcal{O}_V, \mathcal{F}) \cong \Gamma(V, \mathcal{F})\) of
  Lemma~\ref{lem:jshriek_corepr}, taken componentwise; its naturality square in \(\mathcal{F}\) is
  exactly the naturality of that bijection in the coefficient sheaf. The components are
  isomorphisms, so the assembled transformation is a natural isomorphism. Both functors are
  additive (Lemma~\ref{lem:sectionsFunctor_additive} and the additivity of a hom-functor).
\end{proof}

\begin{lemma}
[Right derived functors transport along a natural isomorphism]
  \label{lem:rightDerivedNatIso}
  \lean{AlgebraicGeometry.rightDerivedNatIso}
  Let \(\mathcal{A}\) be an abelian category with enough injectives, \(\mathcal{B}\) abelian, and
  \(F, G : \mathcal{A} \to \mathcal{B}\) additive functors. A natural isomorphism \(F \cong G\)
  induces, for every \(n\), a natural isomorphism of right derived functors
  \[
    F.\mathrm{rightDerived}\,n \;\cong\; G.\mathrm{rightDerived}\,n.
  \]
\end{lemma}
\begin{proof}
  Right derivation is functorial in the functor argument: a natural transformation \(F \to G\)
  induces a natural transformation \(F.\mathrm{rightDerived}\,n \to G.\mathrm{rightDerived}\,n\),
  compatibly with composition and identities. Applying this to the hom and inverse of the given
  isomorphism \(F \cong G\) yields two derived natural transformations, and the composition and
  identity compatibilities show they are mutually inverse; hence
  \(F.\mathrm{rightDerived}\,n \cong G.\mathrm{rightDerived}\,n\).
\end{proof}

\begin{lemma}[The canonical isomorphism of an affine open with its spectrum]
  \label{lem:isoSpec_mathlib}
  \lean{AlgebraicGeometry.IsAffineOpen.isoSpec}
  \mathlibok
  \textit{Provided by Mathlib.}
  Let \(V \subseteq U\) be an affine open of a scheme \(U\). Then there is a canonical isomorphism
  of schemes
  \[
    V \;\cong\; \operatorname{Spec}\Gamma(V, \mathcal{O}_U),
  \]
  natural in the affine open, identifying \(V\) with the spectrum of its ring of sections.
\end{lemma}

\begin{lemma}
[Serre vanishing transports along the spectrum isomorphism of an affine open]
  \label{lem:sectionsFunctor_isoSpec_transport}
  \lean{AlgebraicGeometry.sectionsFunctorIsoSpecTransport_TODO}
  % NOTE: build target. The transport intermediate that carries the pinned $\top$-case Serre
  % vanishing (lem:affine_serre_vanishing, stated for $j_!\mathcal{O}_{\top}$ on a $\Spec R$) to a
  % general affine open. Lean name is a TODO placeholder until a prover lands the declaration.
  \uses{lem:isoSpec_mathlib, lem:sectionsFunctorCorepIso, lem:rightDerivedNatIso,
    lem:jshriek_corepr, lem:affine_serre_vanishing}
  Let \(V\) be an affine open of a scheme \(U\) and \(\mathcal{H}\) a quasi-coherent
  \(\mathcal{O}_U\)-module. Then for every \(q \geq 1\) the absolute cohomology
  \(H^q(V, \mathcal{H}) = \operatorname{Ext}^q(j_!\mathcal{O}_V, \mathcal{H})\) vanishes. Concretely:
  the canonical scheme isomorphism \(V \cong \operatorname{Spec}\Gamma(V, \mathcal{O}_U)\) of
  Lemma~\ref{lem:isoSpec_mathlib} carries the sections functor \(\Gamma(V, -)\) to the
  global-sections functor \(\Gamma(\top, -)\) on \(\operatorname{Spec}\Gamma(V, \mathcal{O}_U)\),
  hence \(j_!\mathcal{O}_V\) to \(j_!\mathcal{O}_\top\); transporting the right-derived vanishing
  across this identification reduces \(H^q(V, \mathcal{H})\) to the \(\top\)-case Serre vanishing
  of Lemma~\ref{lem:affine_serre_vanishing}.
\end{lemma}
\begin{proof}
  \uses{lem:isoSpec_mathlib, lem:sectionsFunctorCorepIso, lem:rightDerivedNatIso,
    lem:jshriek_corepr, lem:affine_serre_vanishing}
  Because \(V\) is an affine open it is an affine scheme, so the canonical morphism
  \(V \to \operatorname{Spec}\Gamma(V, \mathcal{O}_U)\) is an isomorphism
  (Lemma~\ref{lem:isoSpec_mathlib}). This scheme isomorphism induces an equivalence of the module
  categories \(V.\mathrm{Modules} \simeq (\operatorname{Spec}\Gamma(V,\mathcal{O}_U)).\mathrm{Modules}\)
  under which the global-sections functor \(\Gamma(V, -)\) corresponds to
  \(\Gamma(\top, -)\) and, by corepresentability (Lemma~\ref{lem:sectionsFunctorCorepIso} and
  Lemma~\ref{lem:jshriek_corepr}), the corepresenting object \(j_!\mathcal{O}_V\) corresponds to
  \(j_!\mathcal{O}_\top\) on the spectrum. The induced natural isomorphism of additive
  sections functors transports their right derived functors by
  Lemma~\ref{lem:rightDerivedNatIso}; hence \(H^q(V, \mathcal{H})\) is identified with
  \(H^q(\operatorname{Spec}\Gamma(V, \mathcal{O}_U), \mathcal{H}')\) for the transported coefficient
  \(\mathcal{H}'\), which vanishes for \(q \geq 1\) by the \(\top\)-case Serre vanishing of
  Lemma~\ref{lem:affine_serre_vanishing}.
\end{proof}

